class Solution {
    public int getMaxRepetitions(String s1, int n1, String s2, int n2) {
        int m = s2.length(), cnt = 0;
        int[] dp = new int[m + 1];
        for (int i = 0; i < n1; i++) {
            for (int j = 0; j < s1.length(); j++) {
                if (s1.charAt(j) == s2.charAt(cnt % m)) {
                    cnt++;
                    if (cnt % m == 0) {
                        dp[(cnt / m) % (m + 1)] = i + 1;
                    }
                }
            }
        }
        return dp[n2] / n1;
    }
}
